        Level = LogLevel.Error,
        EventName = "InboundSyncFailed",
        Message = "Inbound sync failed for external list {ExternalId}"
    )]
    public static partial void LogInboundSyncFailed(
        this ILogger logger,
        Exception ex,
        string externalId
    );
}

