using Microsoft.AspNetCore.SignalR;
using Microsoft.Extensions.Options;
using Quartz;
using TodoApi.Application.Sync;
using TodoApi.Infrastructure;
using TodoApi.Infrastructure.Hubs;
using TodoApi.Infrastructure.Persistence;
using TodoApi.Infrastructure.Settings;

namespace TodoApi.Application.Jobs;

[DisallowConcurrentExecution]
public sealed class OutboundSyncJob(
    IServiceScopeFactory scopeFactory,
    IHubContext<NotificationHub> hub,
    IClock clock,
    IOptions<ProcessOptions> optionsAccessor,
    ILogger<OutboundSyncJob> logger
) : IJob
{
    private readonly ProcessOptions _options = optionsAccessor.Value;

    public async Task Execute(IJobExecutionContext context)
    {
        ArgumentNullException.ThrowIfNull(context);

        var batchSize = _options.BatchSize;
        await using var scope = scopeFactory.CreateAsyncScope();

        var syncEventRepo = scope.ServiceProvider.GetRequiredService<ISyncEventRepository>();
        var dispatcher = scope.ServiceProvider.GetRequiredService<SyncEventDispatcher>();
        var uow = scope.ServiceProvider.GetRequiredService<IUnitOfWork>();

        var pending = await syncEventRepo
            .GetPendingAsync(50, context.CancellationToken)
            .ConfigureAwait(false);
        var coalesced = Coalesce(pending);
        var processed = 0;
        var failed = 0;
        var sinceLastFlush = 0;

        foreach (var evt in coalesced)
        {
            try
            {
                await dispatcher
                    .DispatchAsync(evt, context.CancellationToken)
                    .ConfigureAwait(false);
                evt.MarkCompleted(clock.UtcNow);
                processed++;
            }
            catch (Exception ex)
            {
                evt.MarkFailed(ex.Message, clock.UtcNow);
                failed++;
                logger.LogOutboundSyncFailed(ex, evt.EntityType, evt.EventType, evt.EntityId);
            }

            sinceLastFlush++;
            if (sinceLastFlush < batchSize)
            {
                continue;
            }

            await uow.SaveChangesAsync(context.CancellationToken).ConfigureAwait(false);
            sinceLastFlush = 0;
        }

        if (sinceLastFlush > 0)
        {
            await uow.SaveChangesAsync(context.CancellationToken).ConfigureAwait(false);
        }

        if (processed + failed > 0)
        {
            await hub
                .Clients.All.SendAsync(
                    "OutboundSyncJob",
                    new { Processed = processed, Failed = failed },
                    context.CancellationToken
                )
                .ConfigureAwait(false);
        }
    }

    private static IEnumerable<Data.Entities.SyncEvent> Coalesce(
        IEnumerable<Data.Entities.SyncEvent> events
    )
    {
        return events
            .GroupBy(e => e.EntityId)
            .Select(g => g.OrderByDescending(e => e.CreatedAt).First());
    }
}

internal static partial class OutboundSyncJobLoggerDefinition
{
    [LoggerMessage(
        EventId = 900,
        Level = LogLevel.Error,
        EventName = "OutboundSyncFailed",
        Message = "Outbound sync failed for {EntityType}/{EventType} {EntityId}"
    )]
    public static partial void LogOutboundSyncFailed(
        this ILogger logger,
        Exception ex,
        EntityType entityType,
        EventType eventType,
        Guid entityId
    );
}

using System.Text.Json;
using FluentAssertions;
using Microsoft.Extensions.Logging.Abstractions;
using NSubstitute;
using TodoApi.Application.ExternalApi;
using TodoApi.Application.ExternalApi.Payloads;
using TodoApi.Application.Jobs.Strategies;
using TodoApi.Application.Sync;
using TodoApi.Data.Entities;
using TodoApi.Infrastructure.Extensions;

namespace TodoApi.Tests.Application.Jobs.Strategies;

public sealed class TodoListCreatedStrategyTests
{
    private readonly IExternalTodoApiClient _client = Substitute.For<IExternalTodoApiClient>();

    private TodoListCreatedStrategy Sut() =>
        new(_client, NullLogger<TodoListCreatedStrategy>.Instance);

    [Fact]
    public void CanHandle_WhenTodoListCreated_ShouldReturnTrue()
    {
        var evt = new SyncEvent(EntityType.TodoList, GuidV7.NewGuid(), EventType.Created, "{}");
        Sut().CanHandle(evt).Should().BeTrue();
    }

    [Fact]
    public void CanHandle_WhenTodoListUpdated_ShouldReturnFalse()
    {
        var evt = new SyncEvent(EntityType.TodoList, GuidV7.NewGuid(), EventType.Updated, "{}");
        Sut().CanHandle(evt).Should().BeFalse();
    }

    [Fact]
    public async Task ExecuteAsync_WhenCalled_ShouldPostPayloadToExternalApiWithCorrelationHeader()
    {
        var id = GuidV7.NewGuid();
        var payload = new TodoListCreatedPayload(id, "Groceries");
        var syncEvent = new SyncEvent(
            EntityType.TodoList,
            id,
            EventType.Created,
            JsonSerializer.Serialize(payload)
        );

        _client
            .CreateTodoListAsync(
                Arg.Any<string>(),
                Arg.Any<CreateExternalTodoListRequest>(),
                Arg.Any<CancellationToken>()
            )
            .Returns(
                new ExternalTodoList(
                    "ext-1",
                    id.ToString(),
                    "Groceries",
                    DateTime.UtcNow,
                    DateTime.UtcNow,
                    []
                )
            );

        await Sut().ExecuteAsync(syncEvent, CancellationToken.None);

        await _client
            .Received(1)
            .CreateTodoListAsync(
                syncEvent.CorrelationId.ToString(),
                Arg.Is<CreateExternalTodoListRequest>(r =>
                    r.SourceId == id.ToString() && r.Name == "Groceries"
                ),
                Arg.Any<CancellationToken>()
            );
    }

    [Fact]
    public async Task ExecuteAsync_WhenExternalApiThrows_ShouldPropagate()
    {
        var id = GuidV7.NewGuid();
        var payload = new TodoListCreatedPayload(id, "x");
        var syncEvent = new SyncEvent(
            EntityType.TodoList,
            id,
            EventType.Created,
            JsonSerializer.Serialize(payload)
        );

        _client
            .CreateTodoListAsync(
                Arg.Any<string>(),
                Arg.Any<CreateExternalTodoListRequest>(),
                Arg.Any<CancellationToken>()
            )
            .Returns<ExternalTodoList>(_ => throw new HttpRequestException("boom"));

        var act = async () => await Sut().ExecuteAsync(syncEvent, CancellationToken.None);

        await act.Should().ThrowAsync<HttpRequestException>();
    }
}

