12	namespace TodoApi.Application.Jobs;
13	
14	[DisallowConcurrentExecution]
15	public sealed class InboundSyncJob(
16	    IServiceScopeFactory scopeFactory,
17	    IHubContext<NotificationHub> hub,
18	    ILogger<InboundSyncJob> logger
19	) : IJob
20	{
21	    public async Task Execute(IJobExecutionContext context)
22	    {
23	        ArgumentNullException.ThrowIfNull(context);
24	
25	        await using var scope = scopeFactory.CreateAsyncScope();
26	        var client = scope.ServiceProvider.GetRequiredService<IExternalTodoApiClient>();
27	        var uow = scope.ServiceProvider.GetRequiredService<IUnitOfWork>();
28	        var clock = scope.ServiceProvider.GetRequiredService<IClock>();
29	        var dbContext = scope.ServiceProvider.GetRequiredService<TodoContext>();
30	
31	        var externalLists = await client
32	            .GetAllAsync(context.CancellationToken)
33	            .ConfigureAwait(false);
34	        var synced = 0;
35	
36	        foreach (var externalList in externalLists)
37	        {
38	            try
39	            {
40	                synced += await SyncListAsync(
41	                        externalList,
42	                        dbContext,
43	                        clock,
44	                        context.CancellationToken
45	                    )
46	                    .ConfigureAwait(false);
47	                await uow.SaveChangesAsync(context.CancellationToken).ConfigureAwait(false);
48	            }
49	            catch (Exception ex)
50	            {
51	                logger.LogInboundSyncFailed(ex, externalList.Id);
52	            }
53	        }
54	
55	        if (synced == 0)
56	        {
57	            return;
58	        }
59	
60	        await hub
61	            .Clients.All.SendAsync(
62	                "InboundSyncJob",
63	                new { Synced = synced },
64	                context.CancellationToken
65	            )
66	            .ConfigureAwait(false);
67	    }
68	
69	    private static async Task<int> SyncListAsync(
70	        ExternalTodoList externalList,
71	        TodoContext dbContext,
72	        IClock clock,
73	        CancellationToken ct
74	    )
75	    {
76	        var localList = await ResolveLocalListAsync(externalList, dbContext, ct)
77	            .ConfigureAwait(false);
78	        var synced = 0;
79	        var now = clock.UtcNow;
80	
81	        if (localList is null)
82	        {
83	            localList = new TodoList(externalList.Name, now);
84	            localList.LinkExternal(externalList.Id);
85	            await dbContext.TodoList.AddAsync(localList, ct).ConfigureAwait(false);
86	            synced++;
87	        }
88	        else
89	        {
90	            if (localList.ExternalId is null)
91	            {
92	                localList.LinkExternal(externalList.Id);
93	            }
94	
95	            if (!string.Equals(localList.Name, externalList.Name, StringComparison.Ordinal))
96	            {
97	                localList.Update(externalList.Name, now);
98	                synced++;
99	            }
100	        }
101	
102	        var order = localList.Items.Count;
103	        foreach (var externalItem in externalList.Items)
104	        {
105	            if (IsAlreadyLinked(localList, externalItem))
106	            {
107	                continue;
108	            }
109	
110	            order++;
111	            var item = localList.AddItem(externalItem.Description, order, now);
112	            if (externalItem.Completed)
113	            {
114	                item.Complete(now);
115	            }
116	            item.LinkExternal(externalItem.Id);
117	            synced++;
118	        }
119	
120	        return synced;
121	    }
122	
123	    private static async Task<TodoList?> ResolveLocalListAsync(
124	        ExternalTodoList externalList,
125	        TodoContext dbContext,
126	        CancellationToken ct
127	    )
128	    {
129	        if (Guid.TryParse(externalList.SourceId, out var sourceLocalId))
130	        {
131	            var bySource = await dbContext
132	                .TodoList.Include(l => l.Items)
133	                .FirstOrDefaultAsync(l => l.Id == sourceLocalId, ct)
134	                .ConfigureAwait(false);
135	            if (bySource is not null)
136	            {
137	                return bySource;
138	            }
139	        }
140	
141	        return await dbContext
142	            .TodoList.Include(l => l.Items)
143	            .FirstOrDefaultAsync(l => l.ExternalId == externalList.Id, ct)
144	            .ConfigureAwait(false);
145	    }
146	
147	    private static bool IsAlreadyLinked(TodoList list, ExternalTodoItem externalItem)
148	    {
149	        if (list.Items.Any(i => i.ExternalId == externalItem.Id))
150	        {
151	            return true;
152	        }
153	
154	        if (
155	            Guid.TryParse(externalItem.SourceId, out var localId)
156	            && list.Items.Any(i => i.Id == localId)
157	        )
158	        {
159	            return true;
160	        }
161	
162	        return false;
163	    }
164	}
